library(r3dmol)
af3 &lt;- here::here("data", "CI_af3.pdb")   # AlphaFold3 model (CIF-&gt;PDB, pLDDT in B-factor)
if (file.exists(af3)) {
  struct &lt;- paste(readLines(af3), collapse = "\n"); fmt &lt;- "pdb"
  ms &lt;- 236; me &lt;- 280            # VASYN ± 20 in TuMV CI (P89509 1228-1871)
  walkerA &lt;- 84:92; dech &lt;- 175:178
} else {
  struct &lt;- paste(readLines(here::here("data","CI_esmfold.pdb")), collapse = "\n")
  fmt &lt;- "pdb"; mot &lt;- readLines(here::here("data","CI_esmfold_motif.txt"))
  mval &lt;- function(k) as.integer(sub(paste0("^",k," "), "",
                     grep(paste0("^",k," "), mot, value = TRUE)))
  ms &lt;- mval("motif_start"); me &lt;- mval("motif_end")
  walkerA &lt;- integer(0); dech &lt;- integer(0)
}

v &lt;- r3dmol(width = "100%", height = "540px") |&gt;
  m_add_model(data = struct, format = fmt) |&gt;
  m_set_style(style = m_style_cartoon(color = "#a9c6e8"))
if (length(walkerA)) {
  v &lt;- v |&gt;
    m_add_style(sel = m_sel(resi = c(walkerA, dech)),
                style = m_style_cartoon(color = "#d4ac0d")) |&gt;
    m_add_style(sel = m_sel(resi = c(walkerA, dech)),
                style = m_style_stick(radius = 0.2))
}
v |&gt;
  m_add_style(sel = m_sel(resi = seq(ms, me)), style = m_style_cartoon(color = "#c0392b")) |&gt;
  m_add_style(sel = m_sel(resi = seq(ms, me)), style = m_style_stick(radius = 0.15)) |&gt;
  m_zoom_to() |&gt;
  m_spin(speed = 0.4)






The model shows the canonical two-lobed SF2-helicase architecture, with the Walker-A and DECH catalytic motifs facing the interdomain cleft and the ELM/ DNAzyme-like motif region on a surface-exposed segment. Structure predicted with AlphaFold 3 (Abramson et al. 2024) (fallback ESMFold (Lin et al. 2023)); interactive rendering via r3dmol/3Dmol.js (Rego and Koes 2015).

